"""Test the fix for needs_extensions version comparison."""
import sys
sys.path.insert(0, '.')

from unittest.mock import Mock
from sphinx.extension import verify_needs_extensions
from sphinx.errors import VersionRequirementError

# Test 1: Extension version 0.10.0 should satisfy requirement 0.6.0
print("Test 1: req=0.6.0, ext=0.10.0 (should NOT raise)")
app = Mock()
app.extensions = {'test_ext': Mock(version='0.10.0')}
config = Mock()
config.needs_extensions = {'test_ext': '0.6.0'}
try:
    verify_needs_extensions(app, config)
    print("  PASS: No error raised")
except VersionRequirementError as e:
    print(f"  FAIL: {e}")

# Test 2: Extension version 0.5.0 should NOT satisfy requirement 0.6.0
print("Test 2: req=0.6.0, ext=0.5.0 (should raise)")
app = Mock()
app.extensions = {'test_ext': Mock(version='0.5.0')}
config = Mock()
config.needs_extensions = {'test_ext': '0.6.0'}
try:
    verify_needs_extensions(app, config)
    print("  FAIL: No error raised")
except VersionRequirementError as e:
    print(f"  PASS: Error raised correctly")

# Test 3: Extension version 0.6.0 should satisfy requirement 0.6.0 (equal)
print("Test 3: req=0.6.0, ext=0.6.0 (should NOT raise)")
app = Mock()
app.extensions = {'test_ext': Mock(version='0.6.0')}
config = Mock()
config.needs_extensions = {'test_ext': '0.6.0'}
try:
    verify_needs_extensions(app, config)
    print("  PASS: No error raised")
except VersionRequirementError as e:
    print(f"  FAIL: {e}")

# Test 4: Extension version 'unknown version' should raise
print("Test 4: req=0.6.0, ext=unknown version (should raise)")
app = Mock()
app.extensions = {'test_ext': Mock(version='unknown version')}
config = Mock()
config.needs_extensions = {'test_ext': '0.6.0'}
try:
    verify_needs_extensions(app, config)
    print("  FAIL: No error raised")
except VersionRequirementError as e:
    print(f"  PASS: Error raised correctly")

# Test 5: None needs_extensions should be skipped
print("Test 5: needs_extensions=None (should skip)")
app = Mock()
config = Mock()
config.needs_extensions = None
try:
    verify_needs_extensions(app, config)
    print("  PASS: No error raised")
except Exception as e:
    print(f"  FAIL: {e}")

# Test 6: Missing extension should warn but not raise
print("Test 6: Missing extension (should warn)")
app = Mock()
app.extensions = {}
config = Mock()
config.needs_extensions = {'missing_ext': '1.0'}
try:
    verify_needs_extensions(app, config)
    print("  PASS: No error raised (warning logged)")
except Exception as e:
    print(f"  FAIL: {e}")

print("\nAll tests completed!")
EOF"}

